#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=210,M=1e4+10;
int lst[N][N][2],n,Q,cdt,ans[M][2],A[2],B[M][2];bool a[N][N];
struct Pr{int x,y;bool c;};vector<Pr> q[M<<2];int top,stk[M*N];
inline int F(int x,int y){return (x-1)*n+y;}
int fa[N*N],sz[N*N];inline int fnd(int x){return fa[x]==x?x:fnd(fa[x]);}
inline void add(int ql,int qr,int u,int v,bool c,int l=1,int r=Q,int cur=1)
{
//	if(cur==1)printf("add %d %d (%d --> %d)\n",ql,qr,u,v);
	if(ql<=l&&r<=qr){q[cur].push_back({u,v,c});return;} int mid=(l+r)>>1;
	if(ql<=mid)add(ql,qr,u,v,c,l,mid,cur<<1);if(qr>mid)add(ql,qr,u,v,c,mid+1,r,cur<<1|1);
}
inline void getAns(int l=1,int r=Q,int cur=1)
{
	int lst=top,aa[2]={A[0],A[1]};
	for(Pr v:q[cur])
	{
		int x=fnd(v.x),y=fnd(v.y);
		if(x!=y)
		{
			if(sz[x]>sz[y])swap(x,y);
			fa[x]=y;sz[y]+=sz[x];stk[++top]=x;++A[v.c];
//			printf("Ins %d->%d :: %d %d\n",v.x,v.y,A[0],A[1]);
			
		}
	}
	if(l==r){ans[l][0]=A[0];ans[l][1]=A[1];}
	else
	{
		int mid=(l+r)>>1;
		getAns(l,mid,cur<<1);
		getAns(mid+1,r,cur<<1|1);
	}
	while(top>lst)
	{
		int u=stk[top--];
//		printf("Del %d %d\n",u,fa[u]);
		sz[fa[u]]-=sz[u];fa[u]=u;
//		printf("QAQ :: %d %d\n",u.x,u.y);
	}
	A[0]=aa[0];A[1]=aa[1];
}
int main()
{
//	FIN("1.in");
	n=read();rep(1,n,i)rep(1,n,j)a[i][j]=read();
	rep(2,n,i)rep(1,n,j)if(a[i-1][j]==a[i][j])lst[i][j][0]=1;
	rep(1,n,i)rep(2,n,j)if(a[i][j]==a[i][j-1])lst[i][j][1]=1;
	rep(1,n*n,i)fa[i]=i,sz[i]=1;
	rep(1,n,i)rep(1,n,j)++B[1][a[i][j]];
	Q=read()+1;rep(2,Q,i)
	{
//		printf("%d :: ",i);
		int x=read(),y=read();
		
		if(x!=1)
		{
			if(!lst[x][y][0])lst[x][y][0]=i;
			else add(lst[x][y][0],i-1,F(x,y),F(x-1,y),a[x][y]),lst[x][y][0]=0;
		}
		if(y!=1)
		{
			if(!lst[x][y][1])lst[x][y][1]=i;
			else add(lst[x][y][1],i-1,F(x,y),F(x,y-1),a[x][y]),lst[x][y][1]=0;
		}
		if(x!=n)
		{
			if(!lst[x+1][y][0])lst[x+1][y][0]=i;
			else add(lst[x+1][y][0],i-1,F(x,y),F(x+1,y),a[x][y]),lst[x+1][y][0]=0;
		}
		if(y!=n)
		{
			if(!lst[x][y+1][1])lst[x][y+1][1]=i;
			else add(lst[x][y+1][1],i-1,F(x,y),F(x,y+1),a[x][y]),lst[x][y+1][1]=0;
		}
		a[x][y]^=1;memcpy(B[i],B[i-1],sizeof(B[i]));
		++B[i][a[x][y]];--B[i][a[x][y]^1];		
	}
	
	rep(2,n,i)rep(1,n,j)if(lst[i][j][0])add(lst[i][j][0],Q,F(i,j),F(i-1,j),a[i][j]);
	rep(1,n,i)rep(2,n,j)if(lst[i][j][1])add(lst[i][j][1],Q,F(i,j),F(i,j-1),a[i][j]);
	getAns();rep(2,Q,i)printf("%d %d\n",B[i][1]-ans[i][1],B[i][0]-ans[i][0]);
//	rep(1,Q,i)printf("%d :: %d %d %d %d\n",i,B[i][1],ans[i][1],B[i][0],ans[i][0]); 
}
